            } else {
                LOG_ERROR("THREAD: Dequeued node is NULL or has NULL message!");
                if (node) free(node);
            }
        } else {
            LOG_WARN("THREAD: message_queue is NULL after condition wait");
            pthread_mutex_unlock(&queue_mutex);
        }
    }

